# Whitelist of allowed table names and column names to prevent injection
ALLOWED_TABLES = {
    'products': ['id', 'name', 'description', 'price', 'category', 'created_at', 'updated_at', 'status'],
    'customers': ['id', 'first_name', 'last_name', 'email', 'city', 'state', 'country', 'created_at'],
    'orders': ['id', 'customer_id', 'product_id', 'quantity', 'total_price', 'status', 'order_date'],
}

ALLOWED_OPERATORS = {
    'eq': '=',
    'neq': '!=',
    'gt': '>',
    'gte': '>=',
    'lt': '<',
    'lte': '<=',
    'like': 'LIKE',
    'in': 'IN',
}

ALLOWED_SORT_DIRECTIONS = {'asc', 'desc'}

MAX_LIMIT = 100
DEFAULT_LIMIT = 20


def validate_table(table_name):
    """Validate table name against whitelist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table name. Allowed tables: {', '.join(ALLOWED_TABLES.keys())}")
    return table_name


def validate_column(table_name, column_name):
    """Validate column name against whitelist for the given table."""
    allowed_columns = ALLOWED_TABLES.get(table_name, [])
    if column_name not in allowed_columns:
        raise ValueError(
            f"Invalid column '{column_name}' for table '{table_name}'. "
            f"Allowed columns: {', '.join(allowed_columns)}"
        )
    return column_name


def validate_operator(operator):
    """Validate operator against whitelist."""
    if operator not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator '{operator}'. Allowed operators: {', '.join(ALLOWED_OPERATORS.keys())}")
    return ALLOWED_OPERATORS[operator]


def validate_limit(limit_value):
    """Validate and sanitize limit value."""
    try:
        limit = int(limit_value)
    except (ValueError, TypeError):
        return DEFAULT_LIMIT
    return max(1, min(limit, MAX_LIMIT))


def validate_offset(offset_value):
    """Validate and sanitize offset value."""
    try:
        offset = int(offset_value)
    except (ValueError, TypeError):
        return 0
    return max(0, offset)


def build_secure_query(table, filters=None, sort_by=None, sort_dir=None, limit=None, offset=None, select_columns=None):
    """
    Build a parameterized SQL query securely.
    
    All table/column names are validated against whitelists.
    All user-provided values are passed as parameterized query parameters.
    """
    # Validate table
    validated_table = validate_table(table)

    # Build SELECT clause
    if select_columns:
        validated_columns = []
        for col in select_columns:
            validated_columns.append(f"`{validate_column(validated_table, col)}`")
        select_clause = ', '.join(validated_columns)
    else:
        select_clause = '*'

    # Use backtick-quoted validated table name (already validated against whitelist)
    query = f"SELECT {select_clause} FROM `{validated_table}`"
    params = []

    # Build WHERE clause with parameterized queries
    if filters:
        where_conditions = []
        for f in filters:
            column = validate_column(validated_table, f['column'])
            sql_operator = validate_operator(f['operator'])

            if f['operator'] == 'in':
                # Handle IN operator with parameterized placeholders
                values = f['value'] if isinstance(f['value'], list) else [f['value']]
                if not values:
                    raise ValueError("IN operator requires at least one value")
                placeholders = ', '.join(['%s'] * len(values))
                where_conditions.append(f"`{column}` {sql_operator} ({placeholders})")
                params.extend(values)
            elif f['operator'] == 'like':
                # For LIKE, wrap value with wildcards but still use parameterized query
                where_conditions.append(f"`{column}` {sql_operator} %s")
                # Escape special LIKE characters in the user value, then wrap with %
                escaped_value = f['value'].replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                params.append(f"%{escaped_value}%")
            else:
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(f['value'])

        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)

    # Build ORDER BY clause (validated column and direction)
